INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", 0.0, "2023/09/22 14:59:59", 10002, "2023/06/30 12:00:00", "クローチェ", 2.15, 126401, 2002, 1, 2, -470.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", 0.0, "2023/09/22 14:59:59", 10003, "2023/06/30 12:00:00", "ライラエル", 0.0, 126501, 2002, 1, 1, -470.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", 0.0, "2023/09/22 14:59:59", 10004, "2023/06/30 12:00:00", "ライラエル", 0.0, 126501, 2002, 1, 2, -470.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", 0.0, "2023/12/22 14:59:59", 10005, "2023/09/15 15:00:00", "リンド", 0.0, 127702, 2002, 2, 1, -470.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", 0.0, "2023/12/22 14:59:59", 10006, "2023/09/15 15:00:00", "リンド", 0.0, 127702, 2002, 2, 2, -470.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", 0.0, "2023/12/22 14:59:59", 10007, "2023/09/15 15:00:00", "ヴルム", 0.0, 127802, 2002, 2, 1, -470.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", 0.0, "2023/12/22 14:59:59", 10008, "2023/09/15 15:00:00", "ヴルム", 6.5, 127802, 2002, 2, 2, -470.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", 0.0, "2024/03/22 14:59:59", 10009, "2023/12/15 15:00:00", "アネモネ", 0.0, 129602, 2002, 3, 1, -470.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", 0.0, "2024/03/22 14:59:59", 10010, "2023/12/15 15:00:00", "アネモネ", 0.0, 129602, 2002, 3, 2, -470.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", 0.0, "2024/03/22 14:59:59", 10011, "2023/12/15 15:00:00", "ネフィ=ネラ", 0.0, 129701, 2002, 3, 1, -470.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", 0.0, "2024/03/22 14:59:59", 10012, "2023/12/15 15:00:00", "ネフィ=ネラ", 6.2, 129701, 2002, 3, 2, -470.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (5, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", 0.0, "2024/06/22 14:59:59", 10013, "2024/03/15 15:00:00", "カノン", 3.1, 130301, 2002, 4, 1, -470.0, 3);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", 0.0, "2024/06/22 14:59:59", 10014, "2024/03/15 15:00:00", "カノン", 6.15, 130301, 2002, 4, 2, -470.0, 3);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", 0.0, "2024/06/22 14:59:59", 10015, "2024/03/15 15:00:00", "ナーナ", 0.0, 130401, 2002, 4, 1, -470.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", 0.0, "2024/06/22 14:59:59", 10016, "2024/03/15 15:00:00", "ナーナ", 3.35, 130401, 2002, 4, 2, -470.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", 0.0, "2024/09/22 14:59:59", 10017, "2024/06/15 15:00:00", "ホウオウ", 0.0, 130502, 2002, 5, 1, -470.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", 0.0, "2024/09/22 14:59:59", 10018, "2024/06/15 15:00:00", "ホウオウ", 3.18, 130502, 2002, 5, 2, -470.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (4, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", 0.0, "2024/09/22 14:59:59", 10019, "2024/06/15 15:00:00", "ホウオウ", 0.0, 130503, 2002, 5, 3, -470.0, 4);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", 0.0, "2024/09/22 14:59:59", 10020, "2024/06/15 15:00:00", "ネア", 4.9, 123301, 2002, 5, 1, -470.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", 0.0, "2024/09/22 14:59:59", 10021, "2024/06/15 15:00:00", "ネア", 4.8, 123301, 2002, 5, 2, -470.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", 0.0, "2024/12/22 14:59:59", 10022, "2024/09/15 15:00:00", "カリザ", 4.922, 133301, 2002, 6, 1, -470.0, 3);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (5, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", 0.0, "2024/12/22 14:59:59", 10023, "2024/09/15 15:00:00", "カリザ", 9.638, 133301, 2002, 6, 2, -470.0, 3);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", 0.0, "2024/12/22 14:59:59", 10024, "2024/09/15 15:00:00", "ミーア", 2.88, 133401, 2002, 6, 1, -470.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", 0.0, "2024/12/22 14:59:59", 10025, "2024/09/15 15:00:00", "ミーア", 4.818, 133401, 2002, 6, 2, -470.0, 5);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", 0.0, "2025/03/22 14:59:59", 10026, "2024/12/15 15:00:00", "グレイス", 1.78, 133002, 2002, 7, 1, -470.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (7, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", 0.0, "2025/03/22 14:59:59", 10027, "2024/12/15 15:00:00", "グレイス", 6.15, 133002, 2002, 7, 2, -470.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", 0.0, "2025/03/22 14:59:59", 10028, "2024/12/15 15:00:00", "ヴァイオレット", 4.28, 133102, 2002, 7, 1, -470.0, 6);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", 0.0, "2025/03/22 14:59:59", 10029, "2024/12/15 15:00:00", "ヴァイオレット", 0.0, 133102, 2002, 7, 2, -470.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", 0.0, "2025/06/23 14:59:59", 10030, "2025/03/15 15:00:00", "ルルィ", 5.53, 136902, 2002, 8, 1, -470.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (7, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", 0.0, "2025/06/23 14:59:59", 10031, "2025/03/15 15:00:00", "ルルィ", 6.05, 136902, 2002, 8, 2, -470.0, 9);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", 0.0, "2025/06/23 14:59:59", 10032, "2025/03/15 15:00:00", "デュラン", 0.0, 137001, 2002, 8, 1, -470.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", 0.0, "2025/06/23 14:59:59", 10033, "2025/03/15 15:00:00", "デュラン", 0.0, 137001, 2002, 8, 2, -470.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "おう\n好きなもん持ってきな", 0.0, "2025/09/23 14:59:59", 10034, "2025/06/16 15:00:00", "サツキ", 0.0, 135902, 2002, 9, 1, -470.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (6, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", 0.0, "2025/09/23 14:59:59", 10035, "2025/06/16 15:00:00", "サツキ", 4.935, 135902, 2002, 9, 2, -470.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (5, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", 0.0, "2025/09/23 14:59:59", 10036, "2025/06/16 15:00:00", "ユキノ", 7.441, 135802, 2002, 9, 1, -470.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (7, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", 0.0, "2025/09/23 14:59:59", 10037, "2025/06/16 15:00:00", "ユキノ", 0.0, 135802, 2002, 9, 2, -470.0, 7);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", 0.0, "2025/12/22 14:59:59", 10038, "2025/09/16 15:00:00", "クルル", 2.295, 130901, 2002, 10, 1, -470.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (6, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", 0.0, "2025/12/22 14:59:59", 10039, "2025/09/16 15:00:00", "クルル", 6.281, 130901, 2002, 10, 2, -470.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", 0.0, "2025/12/22 14:59:59", 10040, "2025/09/16 15:00:00", "ヴォルガーノ", 5.549, 137701, 2002, 10, 1, -470.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (6, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", 0.0, "2025/12/22 14:59:59", 10041, "2025/09/16 15:00:00", "ヴォルガーノ", 2.64, 137701, 2002, 10, 2, -470.0, 3);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (4, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", 0.0, "2026/03/23 11:59:59", 10042, "2025/12/15 15:00:00", "ライラエル", 7.642, 132801, 2002, 11, 1, -470.0, 7);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", 0.0, "2026/03/23 11:59:59", 10043, "2025/12/15 15:00:00", "ライラエル", 0.0, 132802, 2002, 11, 2, -470.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", 0.0, "2026/03/23 11:59:59", 10044, "2025/12/15 15:00:00", "クローチェ", 0.0, 134502, 2002, 11, 1, -470.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", 0.0, "2026/03/23 11:59:59", 10045, "2025/12/15 15:00:00", "クローチェ", 3.72, 134501, 2002, 11, 2, -470.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", 0.0, "2026/06/22 11:59:59", 10046, "2026/03/16 12:00:00", "ネフィ＝ネラ", 4.991, 138201, 2002, 12, 1, -470.0, 2);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (4, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", 0.0, "2026/06/22 11:59:59", 10047, "2026/03/16 12:00:00", "ネフィ＝ネラ", 3.877, 138201, 2002, 12, 2, -470.0, 1);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (6, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", 0.0, "2026/06/22 11:59:59", 10048, "2026/03/16 12:00:00", "アラクネ", 1.71, 136001, 2002, 12, 1, -470.0, 4);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", 0.0, "2026/06/22 11:59:59", 10049, "2026/03/16 12:00:00", "アラクネ", 5.32, 136001, 2002, 12, 2, -470.0, 5);
